function LoginBox({ tipo, titulo, Icon, senhaCorreta, onEntrar }) {
  const [senha, setSenha] = useState("");
  const [erro, setErro] = useState(false);

  function tentarEntrar() {
    if (senha === senhaCorreta) {
      setErro(false);
      onEntrar();
    } else {
      setErro(true);
    }
  }

  return (
    <div
      className="w-full sm:w-64 rounded-xl p-6 flex flex-col items-center"
      style={{
        background: "linear-gradient(160deg, #1c1c1e 0%, #0c0c0d 100%)",
        border: "1px solid rgba(255,255,255,0.08)",
        boxShadow: "0 8px 30px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.05)",
      }}
    >
      <div
        className="w-12 h-12 rounded-full flex items-center justify-center mb-3"
        style={{ background: "rgba(255,255,255,0.06)", border: "1px solid rgba(255,255,255,0.1)" }}
      >
        <Icon size={20} className="text-stone-200" />
      </div>
      <h3 className="text-stone-100 font-semibold text-sm mb-4 tracking-wide">{titulo}</h3>
      <div className="relative w-full mb-2">
        <Lock size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-500" />
        <input
          type="password"
          value={senha}
          onChange={(e) => { setSenha(e.target.value); setErro(false); }}
          onKeyDown={(e) => { if (e.key === "Enter") tentarEntrar(); }}
          placeholder="Senha"
          className="w-full rounded-md pl-9 pr-3 py-2 text-sm bg-black/40 text-stone-100 border border-stone-700 focus:outline-none focus:border-stone-400 placeholder:text-stone-500"
        />
      </div>
      {erro ? <p className="text-xs text-rose-400 mb-2 self-start">Senha incorreta.</p> : null}
      <button
        onClick={tentarEntrar}
        className="w-full mt-1 py-2 rounded-md text-sm font-medium text-stone-900 hover:opacity-90"
        style={{ background: "linear-gradient(160deg, #f4f4f5 0%, #d4d4d8 100%)" }}
      >
        Entrar
      </button>
    </div>
  );
}

