function ListaAlunos({ index, loading, onAbrir, onNovoAluno }) {
  const [busca, setBusca] = useState("");
  const [professorFiltro, setProfessorFiltro] = useState("");
  const [ordenarPor, setOrdenarPor] = useState("nome");

  const professores = Array.from(
    new Set(index.map((a) => a.professorResponsavel).filter(Boolean))
  ).sort();

  let listaFiltrada = index.filter((a) => {
    const matchNome = a.nome.toLowerCase().includes(busca.toLowerCase());
    const matchProfessor = !professorFiltro || a.professorResponsavel === professorFiltro;
    return matchNome && matchProfessor;
  });

  listaFiltrada = listaFiltrada.slice().sort((a, b) => {
    if (ordenarPor === "nome") return a.nome.localeCompare(b.nome);
    if (ordenarPor === "professor")
      return (a.professorResponsavel || "").localeCompare(b.professorResponsavel || "");
    if (ordenarPor === "avaliacao_recente")
      return (b.ultimaAvaliacaoData || "").localeCompare(a.ultimaAvaliacaoData || "");
    if (ordenarPor === "avaliacao_antiga")
      return (a.ultimaAvaliacaoData || "9999-99-99").localeCompare(b.ultimaAvaliacaoData || "9999-99-99");
    return 0;
  });

  return (
    <div>
      <div className="flex items-center justify-between mb-5">
        <div>
          <h1 className="text-2xl font-bold text-stone-800" style={{ fontFamily: SANS }}>
            Alunos
          </h1>
          <p className="text-sm text-stone-500">{index.length} cadastrado(s)</p>
        </div>
        <button
          onClick={onNovoAluno}
          className="flex items-center gap-1.5 bg-emerald-700 text-white px-4 py-2 rounded-md text-sm font-medium hover:bg-emerald-800"
        >
          <Plus size={16} /> Novo aluno
        </button>
      </div>

      <div className="flex flex-wrap gap-2 mb-4">
        <div className="relative flex-1 min-w-[200px]">
          <Search size={15} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
          <input
            value={busca}
            onChange={(e) => setBusca(e.target.value)}
            placeholder="Buscar por nome..."
            className={inputClass + " pl-9"}
          />
        </div>
        <Select value={professorFiltro} onChange={(e) => setProfessorFiltro(e.target.value)}>
          <option value="">Todos os professores</option>
          {professores.map((p) => (
            <option key={p} value={p}>{p}</option>
          ))}
        </Select>
        <Select value={ordenarPor} onChange={(e) => setOrdenarPor(e.target.value)}>
          <option value="nome">Ordenar: Nome (A-Z)</option>
          <option value="professor">Ordenar: Professor responsável</option>
          <option value="avaliacao_recente">Ordenar: Última avaliação (mais recente)</option>
          <option value="avaliacao_antiga">Ordenar: Última avaliação (mais antiga)</option>
        </Select>
      </div>

      {loading ? (
        <div className="flex items-center gap-2 text-stone-500 text-sm py-10 justify-center">
          <Loader2 size={16} className="animate-spin" /> Carregando alunos...
        </div>
      ) : listaFiltrada.length === 0 ? (
        <div className="text-center py-16 text-stone-400 border border-dashed border-stone-300 rounded-lg">
          <Users size={28} className="mx-auto mb-2" />
          <p className="text-sm">
            {index.length === 0 ? "Nenhum aluno cadastrado ainda." : "Nenhum aluno encontrado com esses filtros."}
          </p>
        </div>
      ) : (
        <div className="border border-stone-200 rounded-lg overflow-hidden">
          <table className="w-full text-sm">
            <thead className="bg-stone-50 text-stone-500 text-xs uppercase tracking-wide">
              <tr>
                <th className="text-left px-4 py-2.5 font-semibold">Nome</th>
                <th className="text-left px-4 py-2.5 font-semibold">Professor responsável</th>
                <th className="text-left px-4 py-2.5 font-semibold">Última avaliação</th>
                <th className="px-4 py-2.5"></th>
              </tr>
            </thead>
            <tbody>
              {listaFiltrada.map((a) => (
                <tr
                  key={a.id}
                  onClick={() => onAbrir(a.id)}
                  className="border-t border-stone-100 hover:bg-stone-50 cursor-pointer"
                >
                  <td className="px-4 py-3 font-medium text-stone-800">{a.nome}</td>
                  <td className="px-4 py-3 text-stone-600">{a.professorResponsavel || "—"}</td>
                  <td className="px-4 py-3">
                    {a.ultimaAvaliacaoData ? (
                      <span className="font-mono text-stone-600">{formatDateBR(a.ultimaAvaliacaoData)}</span>
                    ) : (
                      <span className="text-amber-600 text-xs font-medium bg-amber-50 px-2 py-0.5 rounded">
                        sem avaliação
                      </span>
                    )}
                  </td>
                  <td className="px-4 py-3 text-right text-stone-400">›</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function NovoAlunoModal({ onCriar, onCancelar }) {
  const [nome, setNome] = useState("");
  const [telefone, setTelefone] = useState("");
  const [email, setEmail] = useState("");
  const [professor, setProfessor] = useState("");
  const [erro, setErro] = useState("");
  const [salvando, setSalvando] = useState(false);

  async function handleSalvar() {
    if (!nome.trim()) {
      setErro("Informe o nome do aluno.");
      return;
    }
    setSalvando(true);
    await onCriar({ nome: nome.trim(), telefone, email, professorResponsavel: professor.trim() });
    setSalvando(false);
  }

  return (
    <div className="fixed inset-0 bg-stone-900/40 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-lg shadow-xl max-w-md w-full p-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="font-bold text-stone-800 text-lg" style={{ fontFamily: SANS }}>Novo aluno</h3>
          <button onClick={onCancelar} className="text-stone-400 hover:text-stone-600">
            <X size={18} />
          </button>
        </div>
        {erro ? <Banner onClose={() => setErro("")}>{erro}</Banner> : null}
        <Field label="Nome completo">
          <TextInput value={nome} onChange={(e) => setNome(e.target.value)} placeholder="Ex: Maria Silva" autoFocus />
        </Field>
        <Field label="Professor responsável">
          <TextInput value={professor} onChange={(e) => setProfessor(e.target.value)} placeholder="Ex: João" />
        </Field>
        <Field label="Telefone">
          <TextInput value={telefone} onChange={(e) => setTelefone(e.target.value)} placeholder="(00) 00000-0000" />
        </Field>
        <Field label="E-mail">
          <TextInput value={email} onChange={(e) => setEmail(e.target.value)} placeholder="opcional" />
        </Field>
        <div className="flex justify-end gap-2 mt-2">
          <button onClick={onCancelar} className="px-3 py-2 text-sm rounded-md text-stone-600 hover:bg-stone-100">
            Cancelar
          </button>
          <button
            onClick={handleSalvar}
            disabled={salvando}
            className="flex items-center gap-1.5 px-4 py-2 text-sm rounded-md bg-emerald-700 text-white hover:bg-emerald-800 disabled:opacity-60"
          >
            {salvando ? <Loader2 size={14} className="animate-spin" /> : <Save size={14} />}
            Cadastrar
          </button>
        </div>
      </div>
    </div>
  );
}

